def _ensure_not_cancelled(value, _name: str = "") -> None:
    if value is CANCELLED:
        console.print("Cancelled.")
        raise SystemExit(0)

logger = logging.getLogger("greennode_agentbase.cli.identity")
configure_logger(logger)

console = Console()

CONFIG_FILE_NAME = ".greennode.json"


def _mask_secret(value: Optional[str], show_tail: int = 4) -> str:
    """Mask a secret for display, optionally showing last few characters."""
    if not value or len(value) <= show_tail:
        return "***"
    return "*" * (len(value) - show_tail) + value[-show_tail:]


def get_identity_client() -> IdentityClient:
    """Get a configured IdentityClient instance.

    Returns:
        IdentityClient instance with IAM credentials
    """
    try:
        iam_credentials = IAMCredentials()
        if not iam_credentials.is_available():
            raise GreenNodeConfigurationError(
                "IAM credentials are required. Set GREENNODE_CLIENT_ID and GREENNODE_CLIENT_SECRET "
                "or run 'greennode identity login'."
            )
        return IdentityClient(iam_credentials=iam_credentials)
    except GreenNodeConfigurationError:
        raise
    except Exception as e:
        console.print(f"[red]Error: Failed to initialize identity client: {e}[/red]")
        raise click.Abort()


@click.group(name="identity", context_settings=CONTEXT_SETTINGS)
def identity_group() -> None:
    """Manage identity and workload configuration.

    This command group provides operations for IAM credentials, workload
    identities, and local config used by deploy and runtime.
    """
    pass


identity_group.add_command(outbound_auth_group, name="outbound-auth")


@identity_group.command(name="whoami")
def whoami() -> None:
    """Show current workload identity and credential status.

    Examples:
        greennode identity whoami
    """
    workload_name = get_config_value("GREENNODE_AGENT_IDENTITY")
    creds = IAMCredentials()
    creds_ok = creds.is_available()

    # Config file path (resolve for display)
    config_path = Path(CONFIG_FILE_NAME).resolve()

    lines = [
        f"Workload identity: [bold]{workload_name or '(not set)'}[/bold]",
        f"Credentials:       [green]configured[/green]" if creds_ok else "Credentials:       [red]missing[/red]",
        f"Config file:       {config_path}",
    ]
    if creds_ok:
        cid = creds.client_id
        lines.append(f"Client ID:         {_mask_secret(cid)}")
        # Do not show secret at all

    console.print(
        Panel(
            "\n".join(lines),
            title="[bold blue]Identity[/bold blue]",
            border_style="blue",
        )
    )


@identity_group.command(name="login")
def login() -> None:
    """Configure IAM credentials, save to config, and create workload identity if needed.

    Prompts for GREENNODE_CLIENT_ID and GREENNODE_CLIENT_SECRET, sets them in the
    current shell, saves to .greennode.json, and creates a workload identity if
    none is set. Do not commit .greennode.json; keep it out of shared environments.

    Examples:
        greennode identity login
    """
    client_id = Prompt.ask("GREENNODE_CLIENT_ID", password=False, default="")
    if not client_id:
        console.print("[red]Error: GREENNODE_CLIENT_ID is required[/red]")
        raise click.Abort()
    secret = Prompt.ask("GREENNODE_CLIENT_SECRET", password=True, default="")
    if not secret:
        console.print("[red]Error: GREENNODE_CLIENT_SECRET is required[/red]")
        raise click.Abort()

    os.environ["GREENNODE_CLIENT_ID"] = client_id
    os.environ["GREENNODE_CLIENT_SECRET"] = secret
    console.print("[green]Credentials set for this session (environment variables).[/green]")

    save_config_value("client_id", client_id)
    save_config_value("client_secret", secret)
    console.print(
        "[yellow]Credentials saved to .greennode.json. "
        "Do not commit this file; keep it out of shared environments.[/yellow]"
    )
    clear_config_cache()

    current = get_config_value("GREENNODE_AGENT_IDENTITY")
    if not current:
        try:
            client = get_identity_client()
            result = run_async_with_cleanup(client, client.create_workload_identity_async())
            name = result.name if result and result.name else "workload"
            save_config_value("agent_identity", name)
            os.environ["GREENNODE_AGENT_IDENTITY"] = name
            clear_config_cache()
            console.print(f"[green]Created and set workload identity: {name}[/green]")
        except (GreenNodeConfigurationError, GreenNodeRequestError) as e:
            console.print(f"[red]Error creating workload identity: {e}[/red]")
            raise click.Abort()
    else:
        console.print(f"[dim]Workload identity already set: {current}[/dim]")


@identity_group.command(name="logout")
def logout() -> None:
    """Clear workload and credentials from .greennode.json.

    Removes agent_identity, client_id, and client_secret from the config file.
    Does not unset GREENNODE_* from the current shell; you must run
    unset GREENNODE_CLIENT_ID GREENNODE_CLIENT_SECRET GREENNODE_AGENT_IDENTITY
    or open a new shell.

    Examples:
        greennode identity logout
    """
    cleared = []
    if remove_config_value("agent_identity"):
        cleared.append("agent_identity (workload identity)")
    clear_config_cache()
    for key in ("client_id", "client_secret"):
        if remove_config_value(key):
            cleared.append(key)
    clear_config_cache()

    if cleared:
        console.print(f"[green]Cleared from config: {', '.join(cleared)}[/green]")
    else:
        console.print("[dim]No matching config keys were stored.[/dim]")

    console.print(
        "\n[yellow]If you set credentials via environment variables, unset them:[/yellow]\n"
        "  unset GREENNODE_CLIENT_ID GREENNODE_CLIENT_SECRET GREENNODE_AGENT_IDENTITY"
    )


@identity_group.group(name="workload")
def workload_group() -> None:
    """Manage workload identities (agent identities)."""
    pass


@workload_group.command(name="create")
@click.option(
    "--name",
    "-n",
    default=None,
    help="Workload identity name (auto-generated if not provided)",
)
@click.option(
    "--set-current",
    is_flag=True,
    default=False,
    help="Set the created identity as current (GREENNODE_AGENT_IDENTITY)",
)
def workload_create(name: Optional[str], set_current: bool) -> None:
    """Create a new workload identity.

    Examples:
        greennode identity workload create
        greennode identity workload create --name my-agent --set-current
    """
    try:
        client = get_identity_client()
        result = run_async_with_cleanup(
            client,
            client.create_workload_identity_async(name=name)
        )
        created_name = result.name if result and result.name else None
        if not created_name:
            console.print("[red]Error: Create succeeded but no identity name returned[/red]")
            raise click.Abort()

        console.print(f"[green]Created workload identity: {created_name}[/green]")

        if set_current:
            save_config_value("agent_identity", created_name)
            os.environ["GREENNODE_AGENT_IDENTITY"] = created_name
            clear_config_cache()
            console.print(f"[green]Set as current identity. Export: GREENNODE_AGENT_IDENTITY={created_name}[/green]")
    except (GreenNodeConfigurationError, GreenNodeRequestError) as e:
        console.print(f"[red]Error: {e}[/red]")
        raise click.Abort()


@workload_group.command(name="use")
@click.argument("name", required=False, default=None)
def workload_use(name: Optional[str]) -> None:
    """Set the current workload identity by name.

    Examples:
        greennode identity workload use my-agent
        greennode identity workload use   # interactive mode
    """
    name = prompt_if_missing(name, "Workload identity name")
    _ensure_not_cancelled(name, "name")
    save_config_value("agent_identity", name)
    os.environ["GREENNODE_AGENT_IDENTITY"] = name
    clear_config_cache()
    console.print(f"[green]Current workload identity set to: {name}[/green]")
    console.print(f"[dim]Export for other shells: export GREENNODE_AGENT_IDENTITY={name}[/dim]")


@workload_group.command(name="update")
@click.argument("name", required=False, default=None)
def workload_update(name: Optional[str]) -> None:
    """Update a workload identity by name.

    Prompts for optional description and allowed return URLs (comma-separated).
    Leave empty to skip. Type 'q' to cancel.

    Examples:
        greennode identity workload update my-agent
        greennode identity workload update   # interactive mode
    """
    name = prompt_if_missing(name, "Workload identity name")
    _ensure_not_cancelled(name, "name")
    desc_val = prompt_optional("Description", default="")
    _ensure_not_cancelled(desc_val, "description")
    urls_val = prompt_optional("Allowed return URLs (comma-separated)", default="")
    _ensure_not_cancelled(urls_val, "allowed return URLs")
    description = desc_val if desc_val else None
    allowed_return_urls = (
        [u.strip() for u in urls_val.split(",") if u.strip()] if urls_val else None
    )
    try:
        client = get_identity_client()
        result = run_async_with_cleanup(
            client,
            client.update_workload_identity_async(
                name,
                description=description,
                allowed_return_urls=allowed_return_urls,
            )
        )
        console.print(f"[green]Updated workload identity: {result.name}[/green]")
        if result.description:
            console.print(f"[dim]Description: {result.description}[/dim]")
        if getattr(result, "updated_at", None):
            console.print(f"[dim]Updated at: {result.updated_at}[/dim]")
    except (GreenNodeConfigurationError, GreenNodeRequestError) as e:
        console.print(f"[red]Error: {e}[/red]")
        raise click.Abort()


@workload_group.command(name="list")
def workload_list() -> None:
    """List workload (agent) identities.

    Prompts for page and size (defaults 1, 10).

    Examples:
        greennode identity workload list
    """
    page_s = prompt_field("Page", default="1")
    _ensure_not_cancelled(page_s, "page")
    size_s = prompt_field("Size", default="10")
    _ensure_not_cancelled(size_s, "size")
    try:
        page = int(page_s)
        size = int(size_s)
    except ValueError:
        console.print("[red]Error: page and size must be integers.[/red]")
        raise click.Abort()
    try:
        client = get_identity_client()
        list_method = getattr(
            client,
            "list_agent_identities_async",
            None,
        )
        if not callable(list_method):
            console.print(
                "[yellow]List operation is not available for this identity API.[/yellow]"
            )
            return

        result = run_async_with_cleanup(client, list_method(page=page - 1, size=size))

        if getattr(result, "content", None) is None:
            console.print("[dim]No identities returned.[/dim]")
            return

        table = Table(title="Workload identities")
        table.add_column("Name", style="cyan")
        table.add_column("Id", style="dim")
        table.add_column("Created", style="dim")

        for item in result.content or []:
            name = getattr(item, "name", "") or ""
            id_ = getattr(item, "id", "") or ""
            created = getattr(item, "created_at", None)
            created_str = str(created) if created else ""
            table.add_row(name, id_, created_str)

        console.print(table)

        total = getattr(result, "total_elements", None)
        total_pages = getattr(result, "total_pages", None)
        if total is not None or total_pages is not None:
            console.print(
                f"\n[dim]Page {page} of {total_pages or 1} "
                f"(Total: {total or len(result.content or [])})[/dim]"
            )
    except (GreenNodeConfigurationError, GreenNodeRequestError) as e:
        console.print(f"[red]Error: {e}[/red]")
        raise click.Abort()
    except AttributeError:
        console.print(
            "[yellow]List operation is not available for this identity API.[/yellow]"
        )


@identity_group.group(name="config")
def config_group() -> None:
    """Show or manage local config."""
    pass


@config_group.command(name="show")
def config_show() -> None:
    """Show config file path and non-sensitive values.

    Examples:
        greennode identity config show
    """
    config_path = Path(CONFIG_FILE_NAME).resolve()
    lines = [f"Config file: [bold]{config_path}[/bold]", ""]

    # Non-sensitive keys we care about (config file keys, not env var names)
    workload = get_config_value("GREENNODE_AGENT_IDENTITY")
    lines.append(f"agent_identity (GREENNODE_AGENT_IDENTITY): {workload or '(not set)'}")

    if not config_path.exists():
        lines.append("\n[dim]File does not exist yet.[/dim]")
    else:
        lines.append("\n[dim]Sensitive keys (client_id, client_secret) are not shown.[/dim]")

    console.print(Panel("\n".join(lines), title="[bold blue]Config[/bold blue]", border_style="blue"))
